{"Name":"AcceptedOffersCreditsGrid","Content":"async function (vars) {
	var g = new GridWidget(vars.element, vars.dataSource);
	g.searchable = true;
	g.filterable = true;
	g.editable = false;
	g.exports = true;
	g.columns = [
		{
			field: "CreditTypeId",
			width: 50,
			title: "[resource_shortdisplayname[CreditTypeId]]",
			template: "#= AcceptedOffers.creditTypes[CreditTypeId-1].name#",
			filterable: false,
			groupable: false,
			sortable: true
		},
		{
			field: "SourceSystemId",
			title: "[resource_shortdisplayname[SourceSystemId]]",
			width: 90
		},
		{
			field: "DebtorName",
			width: 150,
			title: "[resource_shortdisplayname[DebtorName]]",
			filterable: {multi: true, search: true}
		},
		{
			field: "DebtorState",
			template: "#=B2B.transactionStates[DebtorState] #",
			title: "[resource_shortdisplayname[DebtorState]]",
			width: 100,
			filterable: true,
			groupable: false,
			sortable: true,
			values: Object.keys(B2B.transactionStates).map(c => ({id: c, name: B2B.transactionStates[c] })),
		},
		{
			field: "CreditorName",
			title: "[resource_shortdisplayname[CreditorName]]",
			width: 200,
			filterable: {multi: true, search: true}
		},
		{
			field: "CreditorReference",
			title: "[resource_shortdisplayname[CreditorReference]]",
			width: 100,
			template:"#= Companies.filter(r=>r.Perspective == 'Creditor')[0].CompanyReferenceId.split('|')[1] #"
		},
		{
			field: "CreditorState",
			template: "#=B2B.transactionStates[CreditorState] #",
			title: "[resource_shortdisplayname[CreditorState]]",
			width: 100,
			filterable: true,
			groupable: false,
			sortable: true,
			values: Object.keys(B2B.transactionStates).map(c => ({id: c, name: B2B.transactionStates[c] })),
		},
		{
			field: "TaxPoint",
			format: "{0:" + type.dateFormat + "}",
			title: "[resource_shortdisplayname[TaxPoint]]",
			type: "date",
			width: 80,
			filterable: { search: false }
		},
		{
			field: "Value",
			format: "{0:" + type.moneyFormat + "}",
			title: "[resource_shortdisplayname[Value]]",
			width: 100,
			attributes:{style:"text-align:right;"}
		},
		{
			field: "CurrencyId",
			width: 80,
			title: "[resource_shortdisplayname[CurrencyId]]"
		},
		{
			field: "DebtorPaymentDate",
			title: "[resource_displayname[BuyerPaymentDate]]",
			width: 80,
			format: "{0:" + type.dateFormat + "}",
			type: "date",
			groupHeaderTemplate: "[resource_shortdisplayname[BuyerPaymentDate]]: #= kendo.toString(value, 'yyyy-MM-dd')#"
		},
		{
			field: "DueDate",
			format: "{0:" + type.dateFormat + "}",
			title: "[resource_shortdisplayname[DueDate]]",
			type: "date",
			width: 80
		}
	];
	if(g.viewCommand) {
        g.commands.push({ name: "view", icon: "k-i-share", text: "[resource_shortdisplayname[View]]", href: "/Transactions/Credit?Id=#:Id#" });
	}
	if(g.expandView) {
		g.detailTemplate = "<div name='container'></div>";
        g.detailExpand = function (e) {
            var transaction = this.dataItem(e.masterRow);
            var transactionType = "Credit";
            var transactionId = transaction.Id;
            var container = $(e.detailRow).find("div[name=container]");
            container.html("");
            loadComponent(container[0], transactionType, (component) => {
                component.id = transactionId;
                component.backButton = false;
                component.init(session.app, container[0]);
                container.find("button").hide();
                $(container).css("overflow-y", "hidden");
            });
        };
	}
	if(g.viewDialogCommand) {
		g.commands.push({
            name: "viewDialog",
            icon: "k-i-share",
            text: "[resource_shortdisplayname[ViewDialog]]",
            click: function (e, item, grid, widget) {
                var transactionType = "Credit",
                    transactionId = item.Id,
                    d = new Dialog();
                d.title = "[resource_shortdisplayname[TransactionDetails]]";
                d.width = 1630;
                d.height = 800;
                d.init(() => {
                    loadComponent(d.element, transactionType, (component) => {
                        component.id = transactionId;
                        component.backButton = false;
                        component.init(session.app, d.element);
                        $(d.element).find("button").hide();
                        $(d.element).css("overflow-y", "scroll");
                    });
                });
            }
        });
	}
	vars.acceptedOffersCreditsGrid = g;
	return g;
}
