{"Name":"AcceptOffersGrid","Content":"async function (vars) {
	var g = new GridWidget(vars.element, vars.dataSource);
	g.editable = false;
	g.searchable = true;
	g.search = {
		fields: ["DebtorName", "CreditorName", "Number"]
	};
	g.filterable = true;
	g.groupable = true;
	g.exports = true;
	g.commands.push({
		name: "view",
		icon: "k-i-share",
		text: "[resource_displayname[View]]",
		href: "/EarlyPayments/Offer?Id=#:Id#"
	});
	g.columns = [
		{ 
			field: "ExpiryDate", 
			title: "[resource_displayname[ExpiryDate]]", 
			description: "[resource_description[ExpiryDate]]", 
			format: "{0:" + type.dateFormat + "}", 
			type: "date",
            width: "[theme[columns.date]]"
		},
		{ 
			field: "DebtorName", 
			title: "[resource_displayname[DebtorName]]", 
			description: "[resource_description[DebtorName]]", 
			filterable: { multi: true, search: true } 
		},
		{ 
			field: "CreditorName", 
			title: "[resource_displayname[CreditorName]]", 
			description: "[resource_description[CreditorName]]", 
			filterable: { multi: true, search: true } 
		},
		{ 
			field: "Number", 
			title: "[resource_displayname[Number]]", 
			description: "[resource_description[Number]]",
            width: "[theme[columns.small]]"
		},
		{ 
			field: "FundableValue", 
			title: "[resource_displayname[FundableValue]]", 
			description: "[resource_description[FundableValue]]",  
			format: "{0:" + type.moneyFormat + "}", 
			attributes: { style:"text-align:right;" }
		},
		{ 
			field: "Value", 
			title: "[resource_displayname[OfferValue]]", 
			description: "[resource_description[OfferValue]]", 
			format: "{0:" + type.moneyFormat + "}", 
			attributes:{style:"text-align:right;"}
		},
		{ 
			field: "Cost", 
			title: "[resource_displayname[Cost]]", 
			description: "[resource_description[Cost]]", 
			format: "{0:" + type.moneyFormat + "}", 
			attributes:{style:"text-align:right;"} 
		},
		{
			field: "CurrencyId",
			title: "[resource_shortdisplayname[CurrencyId]]",
			description: "[resource_description[CurrencyId]]",
			filterable: {
				multi: true,
				search: true,
				dataSource: (vars.app.Config.B2B.Currencies || []).map(c => ({ id: c, name: c }))
			},
			values: (vars.app.Config.B2B.Currencies || []).map(c => ({ id: c, name: c }))
		},
		{ 
			field: "EarliestRelatedTaxPoint", 
			title: "[resource_displayname[EarliestRelatedTaxPoint]]", 
			description: "[resource_description[EarliestRelatedTaxPoint]]",  
			format: "{0:" + type.dateFormat + "}", 
			type: "date", 
			groupHeaderTemplate: "[resource_shortdisplayname[EarliestRelatedTaxPoint]]: #= kendo.toString(value, 'yyyy-MM-dd')#",
            width: "[theme[columns.date]]" 
		},
		{ 
			field: "DebtorPaymentDate", 
			title: "[resource_displayname[BuyerPaymentDate]]", 
			description: "[resource_description[BuyerPaymentDate]]", 
			format: "{0:" + type.dateFormat + "}", 
			type: "date", 
			groupHeaderTemplate: "[resource_shortdisplayname[BuyerPaymentDate]]: #= kendo.toString(value, 'yyyy-MM-dd')#",
            width: "[theme[columns.date]]" 
		},
		{ 
			field: "DueDate", 
			title: "[resource_displayname[FunderPaymentDate]]", 
			description: "[resource_description[FunderPaymentDate]]", 
			format: "{0:" + type.dateFormat + "}", 
			type: "date", 
			groupHeaderTemplate: "[resource_shortdisplayname[FunderPaymentDate]]: #= kendo.toString(value, 'yyyy-MM-dd')#",
            width: "[theme[columns.date]]"
		}
	];
	if(g.expandView) {
		g.detailTemplate = "<div name='container'></div>";
        g.detailExpand = function (e) {
            var transaction = this.dataItem(e.masterRow);
            var transactionType = "Offer";
            var transactionId = transaction.Id;
            var container = $(e.detailRow).find("div[name=container]");
			if(!$(container).attr("loaded")) {
				$(container).attr("loaded", "true");
				container.html("");
				loadComponent(container[0], transactionType, (component) => {
					component.id = transactionId;
					component.backButton = false;
					component.init(session.app, container[0]);
					container.find("button").hide();
					$(container).css("overflow-y", "hidden");
				});
			}
        };
	}
	return g;
}
