{"Name":"ApprovalHistoryGrid","Key":"B2B","Content":"async function (variables) {
    var approvalHistoryGrid = new GridWidget(variables.element, variables.dataSource);
    approvalHistoryGrid.columns = [
        { field: "State", type: "string", title: "[resource_shortdisplayname[requestState]]", template: "<span class='k-icon #=UserOnboardingAdmin.iconStates[State]#'></span>" },
        { field: "email", type: "string", title: "[resource_shortdisplayname[userEmail]]", template: "#=JSON.parse(DataJson).fields[0].email#" },
        { field: "companyName", type: "string", title: "[resource_shortdisplayname[companyName]]", template: "#=JSON.parse(DataJson).fields[1].companyName#" },
        { field: "CreatedOn", type: "date", title: "[resource_shortdisplayname[requestDate]]", format: "{0:" + type.dateFormat + "}" },
        { field: "CreatedBy", title: "[resource_shortdisplayname[CreatedBy]]" },
        { field: "requestType", type: "string", title: "[resource_shortdisplayname[requestType]]", template: "#=JSON.parse(DataJson).fields[2].requestType ? UserOnboardingAdmin.requestTypes[JSON.parse(DataJson).fields[2].requestType.value] : ''#" },
    ];
    approvalHistoryGrid.editable = false;
    approvalHistoryGrid.sortable = false;
    approvalHistoryGrid.filterable = false;
    approvalHistoryGrid.pageable = false;
    approvalHistoryGrid.groupable = false;
    variables.ApprovalHistoryGrid = approvalHistoryGrid;
    return approvalHistoryGrid;
}","CreatedOn":"2023-03-12T19:02:18.168Z","LastUpdated":"2023-03-12T19:02:18.168Z"}

