{"Name":"CreateApp","Content":"function (args) {
    var app = {
        DefaultCultureId: args.DefaultCultureId,
        Name: args.AppName,
        Domain: args.AppPath,
        DefaultTheme: args.DefaultTheme,
        ConfigJson: JSON.stringify(args.ConfigJson, null, 2)
    };
    if (args.SourceSystem && app.ConfigJson.hasOwnProperty("B2B") && app.ConfigJson.B2B.hasOwnProperty("SourceSystem")) {
        app.ConfigJson.B2B.SourceSystem = args.SourceSystem.Id;
    }
    if (args.TransactionSourceSystem && app.ConfigJson.hasOwnProperty("B2B") && app.ConfigJson.B2B.hasOwnProperty("TransactionSource")) {
        app.ConfigJson.B2B.TransactionSource = args.TransactionSourceSystem.Id;
    }
    if (args.RootBucket && app.ConfigJson.hasOwnProperty("B2B") && app.ConfigJson.B2B.hasOwnProperty("RootBucket")) {
        app.ConfigJson.B2B.RootBucket = args.RootBucket.Id;
    }
    return api.add("Core/App", app);
}","CreatedOn":"2021-09-24T09:36:41.807Z","LastUpdated":"2021-09-24T09:36:41.807Z","Key":"Core"}

{"Name":"CreateBucketStructure","Key":"B2B","Content":"getAppConfig: async function(vars) {
	vars.App = await api.get("Core/App(" + vars.App.Id + ")");
	vars.App.Config = JSON.parse(vars.App.ConfigJson);
},
createRootBucket: async function (vars) {
	vars.RootBucket = await api.post("B2B/Bucket/CreateStructure?withSystem=" + vars.App.Config.B2B.SourceSystem);
},
updateAppB2B: async function(vars) {
	vars.App = await api.get("Core/App(" + vars.App.Id + ")");
	vars.App.Config = JSON.parse(vars.App.ConfigJson);
	vars.App.Config.B2B.RootBucket = vars.RootBucket.Id;
	vars.App.ConfigJson = JSON.stringify(vars.App.Config, null, 2);
	delete vars.App.Config;
	vars.App = await api.update("Core/App(" + vars.App.Id + ")", vars.App);
	$.ajax({ type: "DELETE", url: "../?key=app", beforeSend: api.beforeSend });//notify the frontend.
}
