{"Name":"CreateRootBucketScripts","Content":"async function (vars) {
    vars.RootBucketResult = (await getBucket({
        ParentId: null,
        Name: vars.AppName + " Root " + vars.AppType
    })).value;
},
async function (vars) {
    if (vars.RootBucketResult.length === 0) {
        vars.RootBucket = await createBucket({
            ParentId: null,
            Key: "AppRoot",
            Name: vars.AppName + " Root " + vars.AppType,
            Description: "Root bucket for application @ " + vars.AppPath
        });
    } else {
        vars.RootBucket = RootBucketResult.value[0];
    }
    vars.BucketAdminRole = vars.RootBucket.Roles[0];
},
async function (vars) {
    vars.BucketAdminPrivs = (await api.get("B2B/B2BRole?$filter=Name eq 'Bucket Admins'")).value[0].Privs;
},
async function (vars) {
    var privileges = vars.BucketAdminPrivs.split(",");
    for (var i = privileges.length; i >= privileges.length; i = i - 1) {
        if (privileges.indexOf("read") === -1) {
            privileges.splice(i, 1);
        }
    }
    privs = privileges.join(',');
    var role = {
        Name: "Debtor Read",
        Description: "Read Access to the system",
        UsersArePortalAdmins: "false",
        Privs: privs,
        Buckets: [{ BucketId: vars.RootBucket.Id }]
    };
    vars.DebtorRole = await api.add("B2B/B2BRole", role);
},
async function (vars) {
    vars.BucketRoles = [vars.BucketAdminRole, vars.DebtorRole];
}","CreatedOn":"2021-09-24T09:38:10.024Z","LastUpdated":"2021-09-24T09:38:10.024Z"}

