{"Name":"GetBucket","Content":"async function getBucket(args) {

    //Grunts... much better for OData query builder task.../one that was sent long ago in Discord.
    //Until then, for simplicity, assumption is always has ParentId.
    var parentIdQuery = "ParentId eq null";
    if (args.ParentId !== null) {
        parentIdQuery = "ParentId eq " + args.ParentId;
    }
    var keyQuery = "";
    var keySet = args.hasOwnProperty("Key");
    if (keySet) {
        keyQuery = "Key eq '" + args.Key + "'";
    }
    var nameQuery = "";
    var nameSet = args.hasOwnProperty("Name");
    if (nameSet) {
        nameQuery = "Name eq '" + args.Name + "'";
    }
    var baseQuery = "";
    if (nameSet && !keySet) {
        baseQuery = nameQuery + " and " + parentIdQuery;
    } else if (nameSet && keySet) {
        baseQuery = nameQuery + " and " + keyQuery + " and " + parentIdQuery;
    } else if (!nameSet && keySet) {
        baseQuery = keyQuery + " and " + parentIdQuery;
    } else if (!nameSet && !keySet) {
        baseQuery = parentIdQuery;
    }
    return api.get("B2B/Bucket?$filter=" + baseQuery + "&$expand=Roles");
}","CreatedOn":"2021-09-24T09:44:41.405Z","LastUpdated":"2021-09-24T09:44:41.405Z"}

