{"Name":"MigrateFunderData","Key":"B2B","Content":"loginExternalApi: async function(vars) {
    console.log("Logging into API instance: " + vars.RemoteAuth.Api);
    vars.ExternalApi = new Api({
        apiRoot: vars.RemoteAuth.Api
    });

    vars.RemoteAuth.token = await vars.ExternalApi.login(vars.RemoteAuth.User, vars.RemoteAuth.Pass, true);
},
migrateFunderData: async function(vars) {
    var destinationSystemId = 'BEL-PACE';
    var filter = "$filter=startswith(Path, '" + vars.TenantId + "') and Key eq 'Funder'";
    var include = "$expand=Companies($expand=Company($expand=References)),Buckets($expand=FundingDetails,Companies($expand=Company($expand=References)))";
    var funderGroupBucketId = (await api.get("B2B/Bucket?$filter=Key eq 'FunderGroup'")).value[0].Id;
    var funders = await vars.ExternalApi.get("B2B/Bucket?" + filter + "&" + include); 

    var mappedFunders = funders.value.map(f => {
        return {  // key details about a bucket
            Key: f.Key,
            Name: f.Name,
            Description: f.Description,
            ParentId: funderGroupBucketId,
            Companies: f.Companies.map(c => c.Company.References[0].Value), // note reference values only 
            Buckets: f.Buckets.map(b => {
                return { // key details about a bucket
                    Key: b.Key,
                    Name: f.Name,
                    Description: f.Description,
                    Companies: b.Companies.map(c => c.Company.References[0].Value), // note reference values only
                    FundingDetails: b.FundingDetails.map(d => {
                        return { // key details about funding details
                            SystemId: destinationSystemId,
                            Name: d.Name,
                            Description: d.Description,
                            CurrencyId: d.CurrencyId,
                            Limit: d.Limit,
                            IsSystematic: d.IsSystematic,
                            Formula: d.Formula,
                            BuyerReferenceId: d.BuyerReferenceId,
                            SupplierReferenceId: d.SupplierReferenceId,
                            FunderReferenceId: d.FunderReferenceId
                        };
                    })
                };
            })
        };
    });

    await api.post("B2B/Import/FundingConfiguration?sourceSystemId=" + destinationSystemId, mappedFunders);
}","CreatedOn":"2023-10-24T13:53:30.653Z","LastUpdated":"2023-10-24T13:53:30.653Z"}

