{"Name":"OfferGrid","Content":"function (vars) {
    var g = new TransactionGrid(vars.element);
    g.editable = false;
    g.transactionId = "Id";
    g.exports = true;
    g.transactionType = "Offer";
    g.addViewCommand = function () {
        this.commands.push({
            name: "view",
            icon: "k-i-share",
            text: "[resource_shortdisplayname[View]]",
            href: "Funding/Offer?Id=#:Id#"
        });
    };
    g.computeColumns = function (withAdded = null, exclude = null, callback) {
        if (withAdded === null) { withAdded = []; }
        if (exclude === null) {
            exclude = [
                "Id", "FunderExternalState", "FundingState", "FunderName", "FunderState", "FunderAcceptanceRule", "DebtorAcceptanceRule", "CreditorAcceptanceRule",
                "ValueBeforeTax", "ValueOfTax", "SourceSystem", "Comment", "DebtorExternalState", "CreditorExternalState", "IsActive",
                "CreationDate", "DeliveryDate", "CaptureDate", "DebtorGeneralLedgerDate", "CreditorGeneralLedgerDate", "AgreedDiscountPaymentDate",
                "DebtorState", "CreditorState", "InvestorSettlementDate", "CreditorSettlementDate", "CreditorPaymentDate", "DueDate", "DebtorPaymentDate"
            ];
        }
        type.columnsFor(this.config.endpoint, withAdded, exclude, (cols) => {
            this.columns = cols;
            this.columns.push({ width: this.commands.length * 80, template: this.commandColumn() });

            this.columns.map((col) => {
                switch (col.Name) {
                    case "OfferStateId":
                        col.order = 3;
                        col.title = "[resource_shortdisplayname[OfferState]]";
                        col.template = "#= B2B.offerStates[OfferStateId] #";
                        col.width = 90;
                        break;
                    case "Effective":
                        col.order = 11;
                        col.title = "[resource_shortdisplayname[Effective]]";
                        col.width = 80;
                        break;
                    case "IssueDate":
                        col.title = "[resource_shortdisplayname[IssueDate]]";
                        col.width = 80;
                        break;
                    case "ExpiresOn":
                        col.format = "{0:" + type.dateFormat + "}";
                        col.title = "[resource_shortdisplayname[ExpiresOn]]";
                        col.width = 80;
                        break;
                    case "InvestorPaymentDate":
                        col.title = "[resource_shortdisplayname[InvestorPaymentDate]]";
                        col.width = 80;
                        break;
                    case "FundableValue":
                        col.title = "[resource_shortdisplayname[FundableValue]]";
                        col.width = 80;
                        break;
                    case "Rate":
                        col.title = "[resource_shortdisplayname[Rate]]";
                        col.width = 80;
                        break;
                    default:
                        this.updateColumn(col);
                        break;
                }
            });
            this.columns.map(col => this.updateColumn(col));
            this.columns = this.columns.sort((a, b) => a.order - b.order);

            if (callback) { callback(); }
        });
    }
    vars.OfferGrid = g;
};
