	g.filterable = true;
	g.groupable = true;
	g.pageable = true;
	g.selectable = true;
	g.exports = true;
	g.toolbar = [
		{ template: "<button class='btn btn-sm btn-primary' name='acceptAll'><span class='k-icon k-i-check'></span>[resource_shortdisplayname[AcceptAll]]</button>" },
		{ template: "<button class='btn btn-sm btn-primary' name='acceptSelected'><span class='k-icon k-i-check'></span>[resource_shortdisplayname[AcceptSelected]]</button>" },
		{ template: "<span class='k-icon k-separator'></span><span class='k-icon k-separator'></span>" },
		{ template: "<input type='text' class='form-control' name='fundingTypeBucketsDropdown' />" },
		{ template: "<input type='text' class='form-control' name='fundingLimitDropdown' />" },
		{ template: "<span class='k-icon k-separator'></span><span class='k-icon k-separator'></span>" },
		{ template: "<button class='btn btn-sm btn-primary' name='applyRecommendations'><span class='k-icon k-i-categorize'></span>[resource_shortdisplayname[selecttovalue]]</button>" },
		{ template: "<input type='text' class='form-control' name='limitValue' title='[resource_displayname[limitvalue]]' />" },
		{ template: "<span class='k-icon k-separator'></span><span class='k-icon k-separator'></span>" },
		{ template: "<p name='offerCostSummary' class='totals'></p>" }
	];
	g.commands.push({
		name: "view",
		icon: "k-i-share",
		text: "[resource_displayname[View]]",
		href: "/EarlyPayments/Offer?Id=#:Id#"
	});
	g.columns = [
		{
			selectable: true,
			width: 50
		},
		{
			field: "ExpiryDate",
			title: "[resource_displayname[ExpiryDate]]",
			description: "[resource_description[ExpiryDate]]",
			format: "{0:" + type.dateFormat + "}",
			type: "date",
			width: "[theme[columns.date]]"
		},
		{
			field: "DebtorName",
			title: "[resource_displayname[DebtorName]]",
			description: "[resource_description[DebtorName]]",
			filterable: { multi: true, search: true }
		},
		{
			field: "CreditorName",
			title: "[resource_displayname[CreditorName]]",
			description: "[resource_description[CreditorName]]",
			filterable: { multi: true, search: true }
		},
		{
			field: "Number",
			title: "[resource_displayname[Number]]",
			description: "[resource_description[Number]]"
		},
		{
			field: "FundableValue",
			title: "[resource_displayname[FundableValue]]",
			description: "[resource_description[FundableValue]]",
			format: "{0:" + type.moneyFormat + "}", attributes: { style: "text-align:right;" }
		},
		{
			field: "Value",
			title: "[resource_displayname[OfferValue]]",
			description: "[resource_description[OfferValue]]",
			format: "{0:" + type.moneyFormat + "}", attributes: { style: "text-align:right;" }
		},
		{
			field: "Cost",
			title: "[resource_displayname[Cost]]",
			description: "[resource_description[Cost]]",
			format: "{0:" + type.moneyFormat + "}",
			attributes: { style: "text-align:right;" }
		},
		{
			field: "CurrencyId",
			title: "[resource_shortdisplayname[CurrencyId]]",
			description: "[resource_description[CurrencyId]]",
			filterable: {
				multi: true,
				search: true,
				dataSource: vars.app.Config.B2B.Currencies.map(c => ({ id: c, name: c }))
			},
			values: vars.app.Config.B2B.Currencies.map(c => ({ id: c, name: c }))
		},

		{
			field: "EarliestRelatedTaxPoint",
			title: "[resource_displayname[EarliestRelatedTaxPoint]]",
			description: "[resource_description[EarliestRelatedTaxPoint]]",
			format: "{0:" + type.dateFormat + "}",
			type: "date",
			groupHeaderTemplate: "[resource_shortdisplayname[EarliestRelatedTaxPoint]]: #= kendo.toString(value, 'yyyy-MM-dd')#",
			width: "[theme[columns.date]]"
		},
		{
			field: "DebtorPaymentDate",
			title: "[resource_displayname[BuyerPaymentDate]]",
			description: "[resource_description[BuyerPaymentDate]]",
			format: "{0:" + type.dateFormat + "}",
			type: "date",
			groupHeaderTemplate: "[resource_shortdisplayname[BuyerPaymentDate]]: #= kendo.toString(value, 'yyyy-MM-dd')#",
			width: "[theme[columns.date]]"
		},
		{
			field: "DueDate",
			title: "[resource_displayname[FunderPaymentDate]]",
			description: "[resource_description[FunderPaymentDate]]",
			format: "{0:" + type.dateFormat + "}",
			type: "date",
			groupHeaderTemplate: "[resource_shortdisplayname[FunderPaymentDate]]: #= kendo.toString(value, 'yyyy-MM-dd')#",
			width: "[theme[columns.date]]"
		}
	];
	if (g.expandView) {
		g.detailTemplate = "<div name='container'></div>";
		g.detailExpand = async function (e) {
			var transaction = this.dataItem(e.masterRow);
			var transactionType = "Offer";
			var transactionId = transaction.Id;
			var container = $(e.detailRow).find("div[name=container]");
			if (!$(container).attr("loaded")) {
				$(container).attr("loaded", "true");
				var component = await loadComponent(container[0], transactionType);
				component.id = transactionId;
				component.backButton = false;
				await component.init(session.app, container[0]);
				container.find("button").hide();
				$(container).css("overflow-y", "hidden");
			}
		};
	}

	g.computeTotals = function () {
		var items = g.gridElement.data("kendoGrid").dataSource.data().filter(r => r.ticked);
		var totalCost = 0;
		var totalItemValue = 0;

		for (var i = 0; i < items.length; i++) {
			totalCost += items[i].Cost;
			totalItemValue += items[i].Value;
		}
		var selectionTotals = "[resource_displayname[selected]]: " + items.length + "," + " [resource_displayname[totalCost]]: " + kendo.toString(totalCost, type.moneyFormat) + "," + " [resource_displayname[totalItemValue]]: " + kendo.toString(totalItemValue, type.moneyFormat);
		$("[name=offerCostSummary]", this.element).html(selectionTotals);
	};

	g.dataBound = function (e) {
		$("input[type=checkbox]", g.gridElement).off("click").on("click", (e) => {
			setTimeout(() => {
				$("tr[data-uid]", g.gridElement).each(function () {
					g.kendoObject.dataItem($(this)).ticked = $("input[type=checkbox]", this).is(":checked");
				});
				g.computeTotals();
			}, 500);
		});
		var items = g.gridElement.data("kendoGrid").items();
		var selectedOffers = g.gridElement.data("kendoGrid").dataSource.data().filter(r => r.ticked).map(o => o.Id);
		for (let i = 0; i < items.length; i++) {
			var offer = g.dataItem(items[i]);
			if (selectedOffers.includes(offer.Id)) {
				g.kendoObject.select(items[i]);
			}
		}
	};
	return g;
}","CreatedOn":"2021-09-23T15:17:50.122Z","LastUpdated":"2021-09-23T15:17:50.122Z","Key":"Funding"}

