{"Name":"RejectOffersGrid","Content":"async function (vars) {
	var g = new GridWidget(vars.element, vars.dataSource);
	g.editable = false;
	g.searchable = true;
	g.filterable = true;
	g.search = {
		fields: ["DebtorName", "CreditorName", "Number"]
	};
	g.groupable = true;
	g.exports = true;
	g.commands.push({
		name: "view",
		icon: "k-i-share",
		text: "[resource_displayname[View]]",
		href: "/Funding/Offer?Id=#:Id#"
	});
	g.columns = [
		{ field: "ExpiryDate", title: "[resource_displayname[ExpiryDate]]", width: 80, format: "{0:" + type.dateFormat + "}", type: "date" },
		{ field: "DebtorName", title: "[resource_displayname[DebtorName]]", filterable: { multi: true, search: true } },
		{ field: "CreditorName", title: "[resource_displayname[CreditorName]]", filterable: { multi: true, search: true } },
		{ field: "Number", title: "[resource_displayname[Number]]", width: 160 },
		{ field: "FundableValue", title: "[resource_displayname[FundableValue]]", width: 100, format: "{0:" + type.moneyFormat + "}", attributes: { style: "text-align:right;" } },
		{ field: "Value", title: "[resource_displayname[OfferValue]]", width: 80, format: "{0:" + type.moneyFormat + "}", attributes: { style: "text-align:right;" } },
		{ field: "Cost", title: "[resource_displayname[Cost]]", width: 60, format: "{0:" + type.moneyFormat + "}", attributes: { style: "text-align:right;" } },
		{
			field: "CurrencyId",
			title: "[resource_shortdisplayname[CurrencyId]]",
			description: "[resource_description[CurrencyId]]",
			filterable: {
				multi: true,
				search: true,
				dataSource: app.Config.B2B.Currencies.map(c => ({ id: c, name: c }))
			},
			values: app.Config.B2B.Currencies.map(c => ({ id: c, name: c }))
		},
		{ field: "DebtorPaymentDate", title: "[resource_displayname[BuyerPaymentDate]]", width: 80, format: "{0:" + type.dateFormat + "}", type: "date", groupHeaderTemplate: "[resource_shortdisplayname[BuyerPaymentDate]]: #= kendo.toString(value, 'yyyy-MM-dd')#" },
		{ field: "DueDate", title: "[resource_displayname[FunderPaymentDate]]", width: 80, format: "{0:" + type.dateFormat + "}", type: "date", groupHeaderTemplate: "[resource_shortdisplayname[FunderPaymentDate]]: #= kendo.toString(value, 'yyyy-MM-dd')#" }
	];
	if (g.expandView) {
		g.detailTemplate = "<div name='container'></div>";
		g.detailExpand = function (e) {
			var transaction = this.dataItem(e.masterRow);
			var transactionType = "Offer";
			var transactionId = transaction.Id;
			var container = $(e.detailRow).find("div[name=container]");
			if (!$(container).attr("loaded")) {
				$(container).attr("loaded", "true");
				container.html("");
				loadComponent(container[0], transactionType, (component) => {
					component.id = transactionId;
					component.backButton = false;
					component.init(session.app, container[0]);
					container.find("button").hide();
					$(container).css("overflow-y", "hidden");
				});
			}
		};
	}
	return g;
}
